import React, { useState } from 'react';
import { useRouter } from 'next/router';

export default function Layout({ children }) {
  const router = useRouter();
  const [mobileOpen, setMobileOpen] = useState(false);

  const navLinks = [
    { href: '/', label: 'Dashboard', icon: DashboardIcon },
    { href: '/books', label: 'Catalog', icon: SearchIcon },
    { href: '/aisles', label: 'Aisles & Shelves', icon: MapIcon },
  ];

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--bg-page)' }}>
      <a href="#main-content" className="skip-nav">Skip to main content</a>

      {/* Top Navigation */}
      <header className="top-nav" role="banner">
        <div className="top-nav-inner">
          {/* Logo */}
          <a href="/" className="nav-logo" aria-label="LibraTrack home">
            <span className="nav-logo-icon" aria-hidden="true">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M4 19.5A2.5 2.5 0 016.5 17H20" />
                <path d="M6.5 2H20v20H6.5A2.5 2.5 0 014 19.5v-15A2.5 2.5 0 016.5 2z" />
                <path d="M8 7h8M8 11h6" />
              </svg>
            </span>
            LibraTrack
          </a>

          {/* Center Nav Links */}
          <nav className="nav-center" aria-label="Main navigation">
            {navLinks.map(link => (
              <a
                key={link.href}
                href={link.href}
                className={`nav-link${router.pathname === link.href ? ' active' : ''}`}
                aria-current={router.pathname === link.href ? 'page' : undefined}
              >
                <link.icon size={15} />
                {link.label}
              </a>
            ))}
          </nav>

          {/* Right side */}
          <div className="nav-right">
            <a href="/login" className="btn btn-primary btn-sm">
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
                <path d="M15 3h4a2 2 0 012 2v14a2 2 0 01-2 2h-4" /><polyline points="10 17 15 12 10 7" /><line x1="15" y1="12" x2="3" y2="12" />
              </svg>
              Sign In
            </a>
            <button
              className="hamburger"
              onClick={() => setMobileOpen(!mobileOpen)}
              aria-expanded={mobileOpen}
              aria-label="Toggle menu"
            >
              <svg width="22" height="22" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24" aria-hidden="true">
                {mobileOpen
                  ? <path strokeLinecap="round" d="M6 18L18 6M6 6l12 12" />
                  : <path strokeLinecap="round" d="M4 6h16M4 12h16M4 18h16" />
                }
              </svg>
            </button>
          </div>
        </div>

        {/* Mobile Nav */}
        {mobileOpen && (
          <nav className="mobile-nav animate-fade-in" aria-label="Mobile navigation">
            {navLinks.map(link => (
              <a
                key={link.href}
                href={link.href}
                className={`nav-link${router.pathname === link.href ? ' active' : ''}`}
                aria-current={router.pathname === link.href ? 'page' : undefined}
                onClick={() => setMobileOpen(false)}
              >
                <link.icon size={14} />
                {link.label}
              </a>
            ))}
          </nav>
        )}
      </header>

      {/* Main Content */}
      <main id="main-content" role="main" style={{ flex: 1, maxWidth: 1200, margin: '0 auto', width: '100%', padding: '1.5rem 1rem' }}>
        {children}
      </main>

      {/* Footer */}
      <footer className="footer">
        © {new Date().getFullYear()} LibraTrack — Library Management System
      </footer>
    </div>
  );
}

function DashboardIcon({ size = 16 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
      <rect x="3" y="3" width="7" height="7" rx="1" /><rect x="14" y="3" width="7" height="7" rx="1" /><rect x="3" y="14" width="7" height="7" rx="1" /><rect x="14" y="14" width="7" height="7" rx="1" />
    </svg>
  );
}
function SearchIcon({ size = 16 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
      <circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" />
    </svg>
  );
}
function MapIcon({ size = 16 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
      <circle cx="12" cy="10" r="3" /><path d="M12 21.7C17.3 16 20 12.3 20 10a8 8 0 10-16 0c0 2.3 2.7 6 8 11.7z" />
    </svg>
  );
}
